package com.dataprocessing.grpc;

import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.*;
import java.nio.file.*;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

public class FileServiceImpl extends FileServiceGrpc.FileServiceImplBase {

    private static final Logger logger = LoggerFactory.getLogger(FileServiceImpl.class);
    private static final String UPLOAD_DIR = "uploads";
    private static final int CHUNK_SIZE = 64 * 1024; // 64KB chunks for streaming

    private final Map<String, FileUploadState> activeUploads = new ConcurrentHashMap<>();
    private final DataProcessor dataProcessor;

    public FileServiceImpl() {
        this(new DefaultDataProcessor());
    }

    public FileServiceImpl(DataProcessor dataProcessor) {
        this.dataProcessor = dataProcessor;
        try {
            Files.createDirectories(Paths.get(UPLOAD_DIR));
        } catch (IOException e) {
            logger.error("Failed to create upload directory", e);
            throw new RuntimeException("Cannot initialize upload directory", e);
        }
    }

    @Override
    public StreamObserver<FileChunk> uploadFile(StreamObserver<UploadStatus> responseObserver) {
        String uploadId = UUID.randomUUID().toString();
        logger.info("Starting file upload session: {}", uploadId);

        return new StreamObserver<FileChunk>() {
            private String filename;
            private long bytesReceived = 0;
            private OutputStream outputStream;
            private boolean hasError = false;

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    if (outputStream == null) {
                        filename = sanitizeFilename(chunk.getFilename());
                        if (filename == null || filename.isEmpty()) {
                            throw new IllegalArgumentException("Invalid filename provided");
                        }
                        Path filePath = Paths.get(UPLOAD_DIR, uploadId + "_" + filename);
                        outputStream = new BufferedOutputStream(
                                new FileOutputStream(filePath.toFile()), 256 * 1024);
                        activeUploads.put(uploadId, new FileUploadState(filename, filePath));
                        logger.info("Receiving file: {} (total size: {} bytes)", filename, chunk.getTotalSize());
                    }

                    byte[] content = chunk.getContent().toByteArray();
                    outputStream.write(content);
                    bytesReceived += content.length;

                    if (bytesReceived % (10 * 1024 * 1024) == 0) {
                        logger.info("Upload progress for {}: {} bytes received", filename, bytesReceived);
                    }
                } catch (Exception e) {
                    hasError = true;
                    logger.error("Error during file upload: {}", e.getMessage(), e);
                    cleanup();
                    responseObserver.onError(
                            io.grpc.Status.INTERNAL
                                    .withDescription("Upload failed: " + e.getMessage())
                                    .asRuntimeException());
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Client error during upload {}: {}", uploadId, t.getMessage());
                cleanup();
            }

            @Override
            public void onCompleted() {
                if (hasError) return;

                try {
                    if (outputStream != null) {
                        outputStream.flush();
                        outputStream.close();
                    }
                    activeUploads.remove(uploadId);

                    UploadStatus status = UploadStatus.newBuilder()
                            .setSuccess(true)
                            .setMessage("File uploaded successfully: " + filename)
                            .setBytesReceived(bytesReceived)
                            .build();

                    logger.info("Upload completed: {} ({} bytes)", filename, bytesReceived);
                    responseObserver.onNext(status);
                    responseObserver.onCompleted();
                } catch (IOException e) {
                    logger.error("Error finalizing upload", e);
                    responseObserver.onError(
                            io.grpc.Status.INTERNAL
                                    .withDescription("Failed to finalize upload: " + e.getMessage())
                                    .asRuntimeException());
                }
            }

            private void cleanup() {
                try {
                    if (outputStream != null) {
                        outputStream.close();
                    }
                    FileUploadState state = activeUploads.remove(uploadId);
                    if (state != null) {
                        Files.deleteIfExists(state.getFilePath());
                    }
                } catch (IOException e) {
                    logger.warn("Cleanup error for upload {}: {}", uploadId, e.getMessage());
                }
            }
        };
    }

    @Override
    public void downloadFile(FileRequest request, StreamObserver<FileChunk> responseObserver) {
        String filename = sanitizeFilename(request.getFilename());
        logger.info("Download requested for file: {}", filename);

        try {
            Path filePath = findFile(filename);
            if (filePath == null) {
                responseObserver.onError(
                        io.grpc.Status.NOT_FOUND
                                .withDescription("File not found: " + filename)
                                .asRuntimeException());
                return;
            }

            long totalSize = Files.size(filePath);
            long offset = 0;

            try (InputStream inputStream = new BufferedInputStream(
                    new FileInputStream(filePath.toFile()), 256 * 1024)) {

                byte[] buffer = new byte[CHUNK_SIZE];
                int bytesRead;

                while ((bytesRead = inputStream.read(buffer)) != -1) {
                    FileChunk chunk = FileChunk.newBuilder()
                            .setFilename(filename)
                            .setContent(com.google.protobuf.ByteString.copyFrom(buffer, 0, bytesRead))
                            .setOffset(offset)
                            .setTotalSize(totalSize)
                            .build();

                    responseObserver.onNext(chunk);
                    offset += bytesRead;
                }
            }

            logger.info("Download completed for file: {} ({} bytes)", filename, totalSize);
            responseObserver.onCompleted();

        } catch (IOException e) {
            logger.error("Error during file download: {}", e.getMessage(), e);
            responseObserver.onError(
                    io.grpc.Status.INTERNAL
                            .withDescription("Download failed: " + e.getMessage())
                            .asRuntimeException());
        }
    }

    @Override
    public StreamObserver<DataMessage> processData(StreamObserver<DataMessage> responseObserver) {
        logger.info("Bidirectional data processing stream opened");

        return new StreamObserver<DataMessage>() {
            private int messagesProcessed = 0;

            @Override
            public void onNext(DataMessage message) {
                try {
                    logger.debug("Processing message: id={}, type={}, payload_size={}",
                            message.getId(), message.getType(), message.getPayload().size());

                    DataMessage result = dataProcessor.process(message);

                    responseObserver.onNext(result);
                    messagesProcessed++;

                    if (messagesProcessed % 1000 == 0) {
                        logger.info("Processed {} messages in current stream", messagesProcessed);
                    }
                } catch (Exception e) {
                    logger.error("Error processing message {}: {}", message.getId(), e.getMessage(), e);

                    DataMessage errorResponse = DataMessage.newBuilder()
                            .setId(message.getId())
                            .setType("ERROR")
                            .setPayload(com.google.protobuf.ByteString.copyFromUtf8(e.getMessage()))
                            .putHeaders("error", e.getClass().getSimpleName())
                            .putHeaders("original_type", message.getType())
                            .build();

                    responseObserver.onNext(errorResponse);
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Client error in bidirectional stream: {}", t.getMessage());
            }

            @Override
            public void onCompleted() {
                logger.info("Bidirectional stream completed. Total messages processed: {}", messagesProcessed);
                responseObserver.onCompleted();
            }
        };
    }

    private String sanitizeFilename(String filename) {
        if (filename == null) return null;
        // Prevent path traversal
        return Paths.get(filename).getFileName().toString();
    }

    private Path findFile(String filename) throws IOException {
        try (var stream = Files.list(Paths.get(UPLOAD_DIR))) {
            return stream
                    .filter(p -> p.getFileName().toString().endsWith("_" + filename))
                    .findFirst()
                    .orElse(null);
        }
    }

    private static class FileUploadState {
        private final String filename;
        private final Path filePath;

        FileUploadState(String filename, Path filePath) {
            this.filename = filename;
            this.filePath = filePath;
        }

        public String getFilename() { return filename; }
        public Path getFilePath() { return filePath; }
    }
}

